import React, { useEffect, useState } from "react";
import axios from "../api";

const SearchForm = () => {
  const [districts, setDistricts] = useState([]);
  const [formData, setFormData] = useState({ district: "" });

  // Fetch districts from backend
  useEffect(() => {
    axios.get("/districts/") // goes to http://127.0.0.1:8000/api/districts/
      .then(res => {
        console.log("Districts fetched:", res.data); // Check browser console
        setDistricts(res.data);
      })
      .catch(err => console.error("Error fetching districts:", err));
  }, []);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div className="container">
      <h2>Bhulekh Land Records</h2>
      <form>
        <div className="form-group">
          <label>District:</label>
          <select
            name="district"
            value={formData.district}
            onChange={handleChange}
          >
            <option value="">--निवडा--</option>
            {districts.map(d => (
              <option key={d.id} value={d.id}>{d.name}</option>
            ))}
          </select>
        </div>
      </form>
    </div>
  );
};

export default SearchForm;
